}
.timeline span, .timeline output {
  color: rgba(226, 234, 255, .76);
  font: 11px ui-monospace, SFMono-Regular, Consolas, monospace;
}
.phase {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  color: rgba(226, 234, 255, .54);
