  padding: 14px;
  display: grid;
  gap: 12px;
}
.tuning-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  color: rgba(226, 234, 255, .82);
  font-size: 12px;
  font-weight: 650;
}
.tuning-head output {
  color: rgba(226, 234, 255, .62);
  font: 11px ui-monospace, SFMono-Regular, Consolas, monospace;
  font-weight: 500;
}
.timing-controls {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 11px 16px;
}
.timing-row {
  display: grid;
  grid-template-columns: 92px 1fr 56px;
  gap: 10px;
  align-items: center;
}
.timing-row label {
  color: rgba(226, 234, 255, .72);
  font-size: 12px;
}
.timing-row output {
  color: rgba(226, 234, 255, .66);
  font: 11px ui-monospace, SFMono-Regular, Consolas, monospace;
  text-align: right;
}
@media (prefers-color-scheme: light) {
.edge-rim-tight { stroke-opacity: .15; }
.edge-rim-soft  { stroke-opacity: .10; }
.edge-contact   { stroke-opacity: .18; }
.cloud-drop-shadow { flood-opacity: .13; }
.timeline, .tuning {
  background: rgba(255, 255, 255, .68);
  border-color: rgba(82, 111, 190, .22);
  box-shadow: 0 20px 70px rgba(58, 78, 130, .14);
}
.phase, .timeline span, .timeline output, .tuning-head output, .timing-row label, .timing-row output { color: rgba(21, 33, 63, .66); }
